          sourceSnippet2: "National Geographic — Qin Shi Huang — Kaisar Pertama Tiongkok",
          source3: "UNESCO World Heritage",
          sourceUrl3: "https://www.google.com/search?q=Qin%20Shi%20Huang%20%E2%80%94%20Kaisar%20Pertama%20Tiongkok",
          sourceSnippet3: "UNESCO World Heritage — Qin Shi Huang — Kaisar Pertama Tiongkok"
