          sourceSnippet2: "History.com — Han Dynasty — The Golden Age of Ancient China",
          source3: "Smithsonian Magazine",
          sourceUrl3: "https://www.smithsonianmag.com/search/?q=Han%20Dynasty%20%E2%80%94%20The%20Golden%20Age%20of%20Ancient%20China",
